(async () => {
  const REPO = 'juxingmaomi/tavern-html-exporter';
  const VERSION = 'v0.30';
  const URL = `https://gcore.jsdelivr.net/gh/${REPO}@${VERSION}/index.js`;

  const loaderState = {
    repo: REPO,
    loadedTag: VERSION,
    source: 'manual',
    url: URL,
    requestedAt: new Date().toISOString(),
  };
  window.__TH_TAVERN_HTML_EXPORTER_LOADER__ = loaderState;

  function popup(type, message) {
    const toastr = window.toastr || (window.parent && window.parent.toastr);
    if (toastr && typeof toastr[type] === 'function') {
      toastr[type](message);
      return;
    }
    if (type === 'error') {
      alert(message);
      return;
    }
    console.log(`[tavern-html-exporter] ${message}`);
  }

  try {
    await import(URL);
    loaderState.loadedAt = new Date().toISOString();
    popup('success', `聊天记录 HTML 导出器已加载 ${VERSION}`);
  } catch (error) {
    loaderState.error = String((error && error.message) || error);
    console.error('[tavern-html-exporter] Load failed.', error);
    popup('error', `聊天记录 HTML 导出器 ${VERSION} 加载失败。请确认 GitHub 已发布这个版本，或稍后再试。`);
  }
})();
